verifySignature.code:
const crypto = require('crypto');
const payload = $input.first().json;
const sig = $input.first().headers['stripe-signature'];
const secret = $env.STRIPE_WEBHOOK_SECRET;

const elements = sig.split(',');
const timestamp = elements.find(e => e.startsWith('t=')).slice(2);
const signature = elements.find(e => e.startsWith('v1=')).slice(3);

const signedPayload = `${timestamp}.${JSON.stringify(payload)}`;
const expected = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');

if (signature !== expected) {
  throw new Error('Invalid Stripe signature');
}

return { json: { verified: true, event: payload } };

eventHandling.code:
const event = $json.event;

switch (event.type) {
  case 'checkout.session.completed':
    return {
      json: {
        event_type: 'payment_success',
        session_id: event.data.object.id,
        amount: event.data.object.amount_total / 100,
        currency: event.data.object.currency,
        customer_email: event.data.object.customer_details.email
      }
    };
  case 'payment_intent.payment_failed':
    return {
      json: {
        event_type: 'payment_failed',
        error: event.data.object.last_payment_error?.message
      }
    };
  default:
    return { json: { event_type: 'other', type: event.type } };
}

vatCalculation.code:
const priceWithoutVat = $json.price;
const vatRate = 0.17;
const vatAmount = priceWithoutVat * vatRate;
const totalPrice = priceWithoutVat + vatAmount;

return {
  json: {
    price_without_vat: priceWithoutVat,
    vat_rate: '17%',
    vat_amount: vatAmount.toFixed(2),
    total_price: totalPrice.toFixed(2),
    currency: 'ILS',
    symbol: '₪'
  }
};

invoiceGeneration.code:
const items = $json.items;
const { DateTime } = require('luxon');

const subtotal = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
const vat = subtotal * 0.17;
const total = subtotal + vat;

return {
  json: {
    invoice_number: `INV-${Date.now()}`,
    date: DateTime.now().setZone('Asia/Jerusalem').toFormat('dd/MM/yyyy'),
    business: {
      name: $env.BUSINESS_NAME,
      id: $env.BUSINESS_ID,
      address: $env.BUSINESS_ADDRESS
    },
    customer: {
      name: $json.customer_name,
      email: $json.customer_email,
      phone: $json.customer_phone
    },
    items: items.map(item => ({
      description: item.name,
      quantity: item.quantity,
      unit_price: item.price,
      total: item.price * item.quantity
    })),
    subtotal: subtotal.toFixed(2),
    vat_rate: '17%',
    vat_amount: vat.toFixed(2),
    total: total.toFixed(2),
    currency: 'ILS'
  }
};

